function focoQtyColor(qty, maxQty) {
  if (qty <= 0 || maxQty <= 0) return "transparent";
  const p = Math.min(1, qty / maxQty);
  const r = Math.round(250 * p + 250 * (1 - p));
  const g = Math.round(50 * p + 204 * (1 - p));
  const b = Math.round(30 * p + 21 * (1 - p));
  return `rgb(${r},${g},${b})`;
}

