function heatColor(pct) {
  const p = Math.max(0, Math.min(1, pct));
  if (p < 0.5) return `rgb(220,${Math.round(p * 2 * 190)},30)`;
  return `rgb(${Math.round((1 - p) * 2 * 220)},195,30)`;
}

function pad3(n) { return String(n).padStart(3, "0"); }
function trackerId(key, n) {
  const [a, b] = key.split(".");
  return `EC-${a}-${b}-TR-${pad3(n)}`;
}
function median(arr) {
  if (!arr.length) return null;
  const s = [...arr].sort((a, b) => a - b);
  return s[Math.floor(s.length / 2)];
}

/* ── geometria por subcampo: bbox, pitch (espaçamento), grupos ─────────── */
function useSubGeometry(key) {
  return useMemo(() => {
    const { t: trackers, cmd } = PLANT[key];
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    for (const [, x, y] of trackers) {
      if (x < minX) minX = x; if (x > maxX) maxX = x;
      if (y < minY) minY = y; if (y > maxY) maxY = y;
    }
    const byY = {};
    trackers.forEach(([, x, y]) => { (byY[y] = byY[y] || []).push(x); });
    const colDiffs = [];
    Object.values(byY).forEach((xs) => {
      xs.sort((a, b) => a - b);
      for (let i = 1; i < xs.length; i++) colDiffs.push(xs[i] - xs[i - 1]);
    });
    const ys = Object.keys(byY).map(Number).sort((a, b) => a - b);
    const rowDiffs = [];
    for (let i = 1; i < ys.length; i++) rowDiffs.push(ys[i] - ys[i - 1]);
    const col = median(colDiffs) || 11;
    const row = median(rowDiffs) || 70;

    const byG = {};
    trackers.forEach((tr) => { (byG[tr[3]] = byG[tr[3]] || []).push(tr); });
    const groups = Object.entries(byG).map(([g, arr]) => {
      const xs = arr.map((a) => a[1]), ys2 = arr.map((a) => a[2]);
      return {
        g, trackers: arr,
        minX: Math.min(...xs), maxX: Math.max(...xs),
        minY: Math.min(...ys2), maxY: Math.max(...ys2),
      };
    }).sort((a, b) => (Number(a.g) || 0) - (Number(b.g) || 0));

    const pad = Math.max(col, row * 0.18);
    const padTop = Math.max(col, row * 0.55);
    return {
      trackers, cmd, minX, maxX, minY, maxY,
      W: maxX - minX + pad * 2, H: maxY - minY + pad + padTop, pad, padTop,
      col, row, groups,
    };
  }, [key]);
}

/* ── status helpers ──────────────────────────────────────────────────── */
function focoKey(cycle, visit) { return `_focos_${cycle}_${visit}`; }
function getFocoQty(statuses, subKey, focoType, cycle, visit) {
  const bucket = statuses[focoKey(cycle, visit)];
  return (bucket && bucket[subKey] && bucket[subKey][focoType]) || 0;
}
function getFocoTotalAll(statuses, subKey, cycle, visit) {
  let total = 0;
  FOCO_TYPES.forEach((ft) => { total += getFocoQty(statuses, subKey, ft.key, cycle, visit); });
  return total;
}
function isFocosLayer(layer) { return layer === "pragas_focos_c1" || layer === "pragas_focos_c2"; }
function focoCycleKey(layer) { return layer === "pragas_focos_c2" ? "c2" : "c1"; }
function getStatus(statuses, subKey, n) {
  const arr = (statuses[subKey] && statuses[subKey][n]) || [];
  return LAYERS.map((_, i) => arr[i] ?? 0);
}
function countDone(statuses, subKey, trackers, layerKey) {
  const idx = LAYER_IDX[layerKey];
  const layer = LAYERS.find((l) => l.key === layerKey);
  const aliases = layer.doneAliases || [];
  let done = 0, prog = 0;
  trackers.forEach(([n]) => {
    const s = getStatus(statuses, subKey, n)[idx];
    if (s === layer.doneIdx || aliases.includes(s)) done++;
    else if (layer.progIdxes.includes(s)) prog++;
  });
  return { done, prog, total: trackers.length, pending: trackers.length - done - prog };
}

