/* ════════════════════════════════════════════════════════════════════════
   MAPA SVG DE UM SUBCAMPO
   ════════════════════════════════════════════════════════════════════════ */
function SubMap({ geo, subKey, statuses, activeLayer, filter, showGroups, selected, onClick, scale }) {
  const { trackers, minX, maxY, W, H, pad, padTop, col, row, groups } = geo;
  const markerW = col * 0.82, markerH = row * 0.5;
  const idx = LAYER_IDX[activeLayer];
  const toX = (x) => x - minX + pad;
  const toY = (y) => maxY - y + padTop;

  const vW = W / scale, vH = H / scale;
  const vX = (W - vW) / 2, vY = (H - vH) / 2;
  const sw = Math.max(W, H);
  return (
    <svg width="100%" height="100%" viewBox={`${vX} ${vY} ${vW} ${vH}`} preserveAspectRatio="xMidYMid meet" style={{ display: "block", cursor: "default" }}>
      {showGroups && groups.map((g) => {
        const gx = toX(g.minX) - markerW * 0.65, gy = toY(g.maxY) - markerH * 0.75;
        const gw = (g.maxX - g.minX) + markerW * 1.3, gh = (g.maxY - g.minY) + markerH * 1.5;
        const stat = countDone(statuses, subKey, g.trackers, activeLayer);
        const complete = stat.done === stat.total;
        return (
          <g key={g.g}>
            <rect x={gx} y={gy} width={gw} height={gh} fill="none"
              stroke={complete ? P.accent : P.border} strokeOpacity={complete ? 0.7 : 0.55}
              strokeDasharray="4 3" strokeWidth={sw * 0.0014} rx={row * 0.06} />
            <text x={gx + 2} y={gy - row * 0.06} fontSize={row * 0.13} fill={complete ? P.accent : P.muted} fontFamily="monospace">
              G{g.g} {stat.done}/{stat.total}
            </text>
          </g>
        );
      })}

      {trackers.map(([n, x, y, g]) => {
        const st = getStatus(statuses, subKey, n);
        const val = st[idx];
        const color = STATE_COLORS[activeLayer][val];
        const dim = filter !== null && val !== filter;
        const isSel = selected === n;
        const cx = toX(x), cy = toY(y);
        const railW = markerW * 0.32;
        const hubH = markerH * 0.13;
        const left = cx - markerW / 2, top = cy - markerH / 2;
        return (
          <g key={n} fill={color} opacity={dim ? 0.16 : 1}
            stroke={isSel ? P.text : "rgba(0,0,0,0.4)"}
            strokeWidth={isSel ? sw * 0.0026 : sw * 0.0005}
            style={{ cursor: "pointer" }}
            onClick={(e) => onClick(n, e.shiftKey)}
          >
            <title>{`${trackerId(subKey, n)}  •  Grupo ${g}\n${LAYERS.map((l, i) => `${l.label}: ${l.states[st[i]]}`).join("\n")}`}</title>
            <rect x={left} y={top} width={railW} height={markerH} rx={railW * 0.35} />
            <rect x={left + markerW - railW} y={top} width={railW} height={markerH} rx={railW * 0.35} />
            <rect x={left} y={cy - hubH / 2} width={markerW} height={hubH} rx={hubH * 0.3} />
          </g>
        );
      })}
    </svg>
  );
}

