/* ════════════════════════════════════════════════════════════════════════
   VISÃO DE UM SUBCAMPO
   ════════════════════════════════════════════════════════════════════════ */
function SubcampoView({ subKey, statuses, setStatuses, activeLayer, setActiveLayer, onNavigate, readOnly, focoType, setFocoType, focoVisit, setFocoVisit }) {
  const geo = useSubGeometry(subKey);
  const [filter, setFilter] = useState(null);
  const [showGroups, setShowGroups] = useState(true);
  const [selected, setSelected] = useState(null);
  const [lastClicked, setLastClicked] = useState(null);
  const [scale, setScale] = useState(1);
  const containerRef = useRef(null);

  const handleWheel = useCallback((e) => {
    e.preventDefault();
    setScale((s) => {
      const factor = e.deltaY < 0 ? 1.08 : 1 / 1.08;
      return Math.min(8, Math.max(1, s * factor));
    });
  }, []);

  const applyToTrackers = useCallback((ns, value) => {
    setStatuses((prev) => {
      const next = { ...prev, [subKey]: { ...(prev[subKey] || {}) } };
      ns.forEach((n) => {
        const cur = getStatus({ [subKey]: next[subKey] }, subKey, n);
        const updated = [...cur];
        updated[LAYER_IDX[activeLayer]] = value;
        if (updated.every((v) => v === 0)) delete next[subKey][n];
        else next[subKey][n] = updated;
      });
      return next;
    });
  }, [subKey, activeLayer, setStatuses]);

  const handleTrackerClick = useCallback((n, shiftKey) => {
    const cur = getStatus(statuses, subKey, n)[LAYER_IDX[activeLayer]];
    const newVal = (cur + 1) % LAYERS.find((l) => l.key === activeLayer).states.length;
    if (shiftKey && lastClicked && lastClicked.subKey === subKey) {
      const lo = Math.min(lastClicked.n, n), hi = Math.max(lastClicked.n, n);
      const ns = [];
      for (let i = lo; i <= hi; i++) ns.push(i);
      applyToTrackers(ns, newVal);
    } else {
      applyToTrackers([n], newVal);
    }
    setSelected(n);
    setLastClicked({ subKey, n });
  }, [statuses, subKey, activeLayer, lastClicked, applyToTrackers]);

  const isFocos = isFocosLayer(activeLayer);
  const safeLayer = isFocos ? "pragas_c1" : activeLayer;
  const stat = isFocos ? { done: 0, prog: 0, total: 0, pending: 0 } : countDone(statuses, subKey, geo.trackers, safeLayer);
  const colors = STATE_COLORS[safeLayer];
  const selStatus = selected != null ? getStatus(statuses, subKey, selected) : null;

  const layer = LAYERS.find((l) => l.key === safeLayer);
  const stateCounts = useMemo(() => {
    if (isFocos) return [];
    const idx = LAYER_IDX[safeLayer];
    const counts = new Array(layer.states.length).fill(0);
    geo.trackers.forEach(([n]) => {
      const v = getStatus(statuses, subKey, n)[idx];
      if (v >= 0 && v < counts.length) counts[v]++;
    });
    return counts;
  }, [geo.trackers, statuses, subKey, safeLayer, isFocos, layer.states.length]);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10, height: "100%" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", flexShrink: 0 }}>
        <button onClick={() => onNavigate(null)} style={{
          display: "flex", alignItems: "center", gap: 5,
          background: "transparent", border: `1px solid ${P.border}`, color: P.muted, borderRadius: 8,
          padding: "7px 13px", cursor: "pointer", fontSize: 12, fontWeight: 600, fontFamily: "inherit",
          transition: "border-color .12s, color .12s",
        }}>← Visão geral</button>
        <h2 style={{ fontSize: 18, fontWeight: 700, color: P.text, margin: 0 }}>SDM {subKey}</h2>
        <select value={subKey} onChange={(e) => onNavigate(e.target.value)} style={{
          marginLeft: "auto", background: P.bg, border: `1px solid ${P.border}`, color: P.text,
          borderRadius: 8, padding: "7px 12px", fontSize: 12, fontFamily: "inherit", fontWeight: 600,
          cursor: "pointer", outline: "none",
        }}>
          {SUB_KEYS.map((k) => <option key={k} value={k}>SDM {k}</option>)}
        </select>
      </div>

      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center", flexShrink: 0 }}>
        <LayerTabs active={activeLayer} onChange={setActiveLayer} />
        {(activeLayer === "pragas_c1" || activeLayer === "pragas_c2" || isFocosLayer(activeLayer)) && (
          <>
            <PragasSubTabs active={activeLayer} onChange={setActiveLayer} />
            {isFocosLayer(activeLayer) && <>
                    <FocoVisitChips active={focoVisit} onChange={setFocoVisit} />
                    <FocoTypeChips active={focoType} onChange={setFocoType} />
                  </>}
          </>
        )}
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <button onClick={() => setActiveLayer(activeLayer === "trator" ? "lavagem" : "trator")} style={{
            padding: "4px 10px", borderRadius: 7,
            border: `1px solid ${activeLayer === "trator" ? P.warn + "66" : P.border}`,
            cursor: "pointer", fontFamily: "inherit", fontSize: 11, fontWeight: 600,
            background: activeLayer === "trator" ? P.warn + "22" : "transparent",
            color: activeLayer === "trator" ? P.warn : P.muted, transition: "all .12s",
          }}>
            Acesso trator
          </button>
          <button onClick={() => setActiveLayer(activeLayer === "trackers" ? "lavagem" : "trackers")} style={{
            padding: "4px 10px", borderRadius: 7,
            border: `1px solid ${activeLayer === "trackers" ? P.purple + "66" : P.border}`,
            cursor: "pointer", fontFamily: "inherit", fontSize: 11, fontWeight: 600,
            background: activeLayer === "trackers" ? P.purple + "22" : "transparent",
            color: activeLayer === "trackers" ? P.purple : P.muted, transition: "all .12s",
          }}>
            Trackers
          </button>
        </div>
      </div>

      {isFocos ? (() => {
        const cyc = focoCycleKey(activeLayer);
        const bucketKey = focoKey(cyc, focoVisit);
        return (
        <div style={{ display: "flex", gap: 14, flex: 1, minHeight: 0 }}>
          <div style={{
            flex: "2 1 420px", background: P.surface, border: `1px solid ${P.border}`, borderRadius: 12,
            padding: 12, display: "flex", alignItems: "center", justifyContent: "center",
          }}>
            <svg width="100%" height="100%" viewBox={`0 0 ${geo.W} ${geo.H}`} preserveAspectRatio="xMidYMid meet" style={{ display: "block" }}>
              {geo.groups.map((g) => {
                const gx = (g.minX - geo.minX + geo.pad) - geo.col * 0.65;
                const gy = (geo.maxY - g.maxY + geo.padTop) - geo.row * 0.75;
                const gw = (g.maxX - g.minX) + geo.col * 1.3;
                const gh = (g.maxY - g.minY) + geo.row * 1.5;
                return (
                  <rect key={g.g} x={gx} y={gy} width={gw} height={gh}
                    fill="none" stroke={P.border} strokeOpacity={0.5}
                    strokeDasharray="4 3" strokeWidth={Math.max(geo.W, geo.H) * 0.0014} rx={geo.row * 0.06} />
                );
              })}
              {geo.trackers.map(([n, x, y]) => {
                const cx = x - geo.minX + geo.pad;
                const cy = geo.maxY - y + geo.padTop;
                return (
                  <rect key={n} x={cx - geo.col * 0.15} y={cy - geo.row * 0.15}
                    width={geo.col * 0.3} height={geo.row * 0.3} rx={2}
                    fill={P.border} opacity={0.3} />
                );
              })}
            </svg>
          </div>

          <div style={{ flex: "1 1 260px", display: "flex", flexDirection: "column", gap: 12, overflowY: "auto" }}>
            <div style={{ background: P.card2, borderRadius: 8, padding: "6px 12px", textAlign: "center" }}>
              <span style={{ color: P.warn, fontSize: 11, fontWeight: 700, fontFamily: "monospace", letterSpacing: 1 }}>
                FOCOS — CICLO {cyc === "c1" ? "1" : "2"} — {focoVisit === "v1" ? "VISITA 1" : "VISITA 2"}
              </span>
            </div>
            {FOCO_TYPES.map((ft) => {
              const bucket = statuses[bucketKey] || {};
              const val = (bucket[subKey] && bucket[subKey][ft.key]) || 0;
              return (
                <div key={ft.key} style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 16 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <span style={{ color: P.text, fontSize: 13, fontWeight: 700, fontFamily: "monospace", flex: 1 }}>{ft.label}</span>
                    <input type="number" min={0} value={val} disabled={readOnly}
                      onChange={(e) => {
                        const v = Math.max(0, parseInt(e.target.value) || 0);
                        setStatuses((prev) => {
                          const focos = { ...(prev[bucketKey] || {}) };
                          const sub = { ...(focos[subKey] || {}) };
                          sub[ft.key] = v;
                          focos[subKey] = sub;
                          return { ...prev, [bucketKey]: focos };
                        });
                      }}
                      style={{
                        width: 80, padding: "8px 10px", borderRadius: 8, fontSize: 16, fontWeight: 700,
                        background: P.bg, border: `1px solid ${P.border}`, color: val > 0 ? P.warn : P.muted,
                        fontFamily: "monospace", textAlign: "center", outline: "none",
                      }} />
                  </div>
                </div>
              );
            })}
          </div>
        </div>
        );
      })() : (
        <>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, flexShrink: 0 }}>
        <FilterChips activeLayer={activeLayer} filter={filter} onChange={setFilter} />
        <label style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: P.muted, cursor: "pointer" }}>
          <input type="checkbox" checked={showGroups} onChange={(e) => setShowGroups(e.target.checked)} />
          Contornos de grupo
        </label>
      </div>

      <div style={{ display: "flex", gap: 14, flex: 1, minHeight: 0 }}>
        <div ref={containerRef} onWheel={handleWheel} style={{
          flex: "2 1 420px", background: P.surface, border: `1px solid ${P.border}`, borderRadius: 12,
          padding: 12, overflow: "hidden", position: "relative",
        }}>
          <div style={{ position: "absolute", top: 10, right: 10, zIndex: 2, display: "flex", gap: 6 }}>
            <button onClick={() => setScale((s) => Math.min(8, s * 1.1))} style={zoomBtnStyle}>＋</button>
            <button onClick={() => setScale((s) => Math.max(1, s / 1.1))} style={zoomBtnStyle}>－</button>
          </div>
          <SubMap geo={geo} subKey={subKey} statuses={statuses} activeLayer={activeLayer}
            filter={filter} showGroups={showGroups} selected={selected}
            onClick={readOnly ? () => {} : handleTrackerClick} scale={scale} />
        </div>

        <div style={{ flex: "1 1 260px", display: "flex", flexDirection: "column", gap: 12, overflowY: "auto" }}>
          <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 10, letterSpacing: 0.5 }}>CLASSIFICAÇÃO — {layer.label.toUpperCase()}</div>
            {layer.states.map((s, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                <div style={{ width: 8, height: 8, borderRadius: "50%", background: STATE_COLORS[activeLayer][i], flexShrink: 0 }} />
                <span style={{ flex: 1, fontSize: 11.5, color: P.muted, fontFamily: "monospace" }}>{s}</span>
                <span style={{ fontSize: 13, fontWeight: 700, color: stateCounts[i] > 0 ? P.text : P.border, fontFamily: "monospace", minWidth: 28, textAlign: "right" }}>
                  {stateCounts[i]}
                </span>
                <span style={{ fontSize: 10.5, color: P.muted, fontFamily: "monospace", width: 34, textAlign: "right" }}>
                  {geo.trackers.length > 0 ? Math.round(stateCounts[i] / geo.trackers.length * 100) + "%" : "—"}
                </span>
              </div>
            ))}
          </div>

          {!readOnly && (
            <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
              <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 8, letterSpacing: 0.5 }}>TRACKER SELECIONADO</div>
              {selected != null ? (
                <div>
                  <div style={{ color: P.text, fontWeight: 700, fontSize: 14, marginBottom: 8, fontFamily: "monospace" }}>{trackerId(subKey, selected)}</div>
                  {LAYERS.filter((l) => !l.hidden).map((l, i) => {
                    const li = LAYERS.indexOf(l);
                    const stateColor = STATE_COLORS[l.key][selStatus[li]];
                    return (
                      <div key={l.key} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: P.muted, width: 96, fontFamily: "inherit" }}>{l.label}</span>
                        <button onClick={() => applyToTrackers([selected], (selStatus[li] + 1) % l.states.length)} style={{
                          display: "flex", alignItems: "center", gap: 5,
                          background: stateColor + "1e", border: `1px solid ${stateColor}55`,
                          color: stateColor, borderRadius: 99, padding: "4px 11px",
                          fontSize: 11, fontWeight: 600, cursor: "pointer", fontFamily: "inherit",
                          transition: "all .12s",
                        }}>
                          <div style={{ width: 6, height: 6, borderRadius: "50%", background: stateColor, flexShrink: 0 }} />
                          {l.states[selStatus[li]]}
                        </button>
                      </div>
                    );
                  })}
                </div>
              ) : <div style={{ color: P.muted, fontSize: 12.5 }}>Toque em um tracker no mapa para ver e editar o status. Shift+clique pinta um intervalo.</div>}
            </div>
          )}

          {!readOnly && (
            <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
              <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 10, letterSpacing: 0.5 }}>MARCAR INTERVALO (1–132)</div>
              <RangeTool activeLayer={activeLayer} onApply={(from, to, val) => {
                const lo = Math.max(1, Math.min(from, to)), hi = Math.min(132, Math.max(from, to));
                const ns = []; for (let i = lo; i <= hi; i++) ns.push(i);
                applyToTrackers(ns, val);
              }} />
            </div>
          )}

          <div style={{ background: P.card, border: `1px solid ${P.border}`, borderRadius: 12, padding: 14 }}>
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginBottom: 10, letterSpacing: 0.5 }}>GRUPOS DE COMANDO</div>
            <GroupPanel geo={geo} subKey={subKey} statuses={statuses} activeLayer={activeLayer}
              onBulk={readOnly ? () => {} : (ns, val) => applyToTrackers(ns, val)} readOnly={readOnly} />
          </div>

          <Legend activeLayer={activeLayer} />
        </div>
      </div>
        </>
      )}
    </div>
  );
}

const zoomBtnStyle = {
  width: 26, height: 26, borderRadius: 6, border: `1px solid ${P.border}`, background: P.card,
  color: P.text, cursor: "pointer", fontSize: 14, fontFamily: "inherit", lineHeight: 1,
};

/* ════════════════════════════════════════════════════════════════════════
   VISÃO GERAL — mapa geográfico real (satélite) com overlay SVG calibrado
   Coordenadas UTM SIRGAS 2000 Zona 24S convertidas para WGS84 lat/lon
   ════════════════════════════════════════════════════════════════════════ */

function utmToLatLon(E, N) {
  const k0 = 0.9996, a = 6378137.0, e2 = 0.00669437999014;
  const lon0 = -39 * Math.PI / 180;
  const e1 = (1 - Math.sqrt(1 - e2)) / (1 + Math.sqrt(1 - e2));
  const x = E - 500000, y = N - 10000000;
  const M = y / k0;
  const mu = M / (a * (1 - e2 / 4 - 3 * e2 ** 2 / 64 - 5 * e2 ** 3 / 256));
  const phi1 = mu
    + (3 * e1 / 2 - 27 * e1 ** 3 / 32) * Math.sin(2 * mu)
    + (21 * e1 ** 2 / 16 - 55 * e1 ** 4 / 32) * Math.sin(4 * mu)
    + (151 * e1 ** 3 / 96) * Math.sin(6 * mu);
  const sp = Math.sin(phi1), cp = Math.cos(phi1), tp = Math.tan(phi1);
  const N1 = a / Math.sqrt(1 - e2 * sp * sp), T1 = tp * tp, C1 = e2 * cp * cp / (1 - e2);
  const R1 = a * (1 - e2) / Math.pow(1 - e2 * sp * sp, 1.5), D = x / (N1 * k0);
  const lat = phi1 - (N1 * tp / R1) * (
    D * D / 2 - (5 + 3 * T1 + 10 * C1 - 4 * C1 * C1 - 9 * e2 / (1 - e2)) * D ** 4 / 24
  );
  const lon = lon0 + (
    D - (1 + 2 * T1 + C1) * D ** 3 / 6
    + (5 - 2 * C1 + 28 * T1 - 3 * C1 * C1 + 8 * e2 / (1 - e2) + 24 * T1 * T1) * D ** 5 / 120
  ) / cp;
  return [lat * 180 / Math.PI, lon * 180 / Math.PI];
}

const PLANT_CENTER_LL = utmToLatLon(457786, 9633887);

// Pre-compute tracker lat/lon for dot rendering at high zoom
const TRACKER_LL = Object.fromEntries(
  SUB_KEYS.map((key) => [
    key,
    PLANT[key].t.map(([n, x, y]) => ({ n, ll: utmToLatLon(x, y) })),
  ])
);

// Pre-compute subcampo outline polygons using real row structure of trackers
const SUBCAMPO_POLY_LL = Object.fromEntries(SUB_KEYS.map((key) => {
  const trackers = PLANT[key].t;

  // Group trackers into rows by Y coordinate (5 m tolerance)
  const rowMap = new Map();
  for (const [, x, y] of trackers) {
    let foundY = null;
    for (const ry of rowMap.keys()) {
      if (Math.abs(ry - y) < 5) { foundY = ry; break; }
    }
    if (foundY === null) rowMap.set(y, { minX: x, maxX: x });
    else {
      const r = rowMap.get(foundY);
      if (x < r.minX) r.minX = x;
      if (x > r.maxX) r.maxX = x;
    }
  }

  const rows = [...rowMap.entries()]
    .map(([y, r]) => ({ y, minX: r.minX, maxX: r.maxX }))
    .sort((a, b) => b.y - a.y); // N → S

  // Half X margin: median gap between adjacent trackers in same row
  const allX = trackers.map((t) => t[1]).sort((a, b) => a - b);
  const xGaps = [];
  for (let i = 1; i < allX.length; i++) {
    const g = allX[i] - allX[i - 1];
    if (g > 0.5 && g < 30) xGaps.push(g);
  }
  xGaps.sort((a, b) => a - b);
  const hx = xGaps.length ? xGaps[Math.floor(xGaps.length / 2)] / 2 : 8;

  // Half Y margin: half the minimum spacing between rows
  const yGaps = rows.slice(0, -1).map((r, i) => r.y - rows[i + 1].y);
  const hy = yGaps.length ? Math.min(...yGaps) / 2 : 36;

  // Staircase polygon: trace left edge N→S, then right edge S→N
  const utmPoly = [
    ...rows.flatMap((r) => [[r.minX - hx, r.y + hy], [r.minX - hx, r.y - hy]]),
    ...[...rows].reverse().flatMap((r) => [[r.maxX + hx, r.y - hy], [r.maxX + hx, r.y + hy]]),
  ];

  return [key, utmPoly.map(([x, y]) => utmToLatLon(x, y))];
}));

function PlantLayer({ statuses, activeLayer, onSelect, heatmap, focoType, focoVisit }) {
  const map = useMap();
  const [, tick] = useReducer((n) => n + 1, 0);
  useMapEvents({ move: tick, zoom: tick, resize: tick });

  const isFocos = isFocosLayer(activeLayer);
  const realLayer = isFocos ? "pragas_c1" : activeLayer;
  const idx = LAYER_IDX[realLayer];
  const size = map.getSize();
  const zoom = map.getZoom();

  const toPixel = (ll) => map.latLngToContainerPoint(L.latLng(ll[0], ll[1]));

  const boxData = SUB_KEYS.map((key) => {
    const trackers = PLANT[key].t;
    const stat = isFocos ? { done: 0, prog: 0, total: 0, pending: 0 } : countDone(statuses, key, trackers, realLayer);
    const pct = stat.total ? stat.done / stat.total : 0;

    const pixPoly = SUBCAMPO_POLY_LL[key].map((ll) => {
      const p = toPixel(ll);
      return { x: p.x, y: p.y };
    });
    const hullStr = pixPoly.map((p) => `${p.x},${p.y}`).join(" ");

    const xs = pixPoly.map((p) => p.x), ys = pixPoly.map((p) => p.y);
    const bx = Math.min(...xs), by = Math.min(...ys);
    const bw = Math.max(...xs) - bx, bh = Math.max(...ys) - by;
    const cx = bx + bw / 2, cy = by + bh / 2;

    const avgHeat = heatmap
      ? trackers.reduce((s, [n]) => s + (LAYER_PCT[realLayer]?.[getStatus(statuses, key, n)[idx]] ?? 0), 0) / (trackers.length || 1)
      : 0;

    const focoCycle = isFocos ? focoCycleKey(activeLayer) : "c1";
    const focoQty = isFocos ? getFocoQty(statuses, key, focoType, focoCycle, focoVisit) : 0;
    const focoTotal = isFocos ? getFocoTotalAll(statuses, key, focoCycle, focoVisit) : 0;

    return { key, stat, pct, hullStr, bx, by, bw, bh, cx, cy, avgHeat, focoQty };
  });

  const focoMax = isFocos ? Math.max(1, ...boxData.map((d) => d.focoQty)) : 1;

  const fPct = heatmap
    ? boxData.reduce((m, { bw, bh }) => Math.min(m, bh * 0.28, bw * 0.30), Infinity)
    : 16;
  const fName = fPct * 0.80;
  const sw = Math.max(0.5, fPct * 0.05);

  const trackerDots = (!isFocos && !heatmap && zoom >= 16)
    ? SUB_KEYS.flatMap((key) => TRACKER_LL[key].map(({ n, ll }) => {
        const pt = toPixel(ll);
        const val = getStatus(statuses, key, n)[idx];
        return { key, n, pt, val };
      }))
    : [];

  return createPortal(
    <svg
      width={size.x} height={size.y}
      style={{ position: "absolute", top: 0, left: 0, zIndex: 500, pointerEvents: "none" }}
    >
      {isFocos ? (
        <>
          {boxData.map(({ key, hullStr, focoQty, cx, cy, bw, bh }) => {
            const color = focoQtyColor(focoQty, focoMax);
            return (
            <g key={key}>
              <polygon points={hullStr}
                fill={focoQty > 0 ? color : "rgba(16,23,41,0.72)"}
                opacity={focoQty > 0 ? 0.75 : 0.72}
                stroke={focoQty > 0 ? color : P.border} strokeWidth={2}
                style={{ pointerEvents: "auto", cursor: "pointer" }} onDoubleClick={() => onSelect(key)} />
              {bw > 24 && bh > 18 && (
                <text x={cx} y={cy - fName * 0.3} fontSize={fName} fill="#fff" fontFamily="monospace"
                  fontWeight="700" textAnchor="middle" dominantBaseline="middle"
                  stroke="rgba(0,0,0,0.7)" strokeWidth={sw} paintOrder="stroke">
                  SDM {key}
                </text>
              )}
              {bw > 24 && (
                <text x={cx} y={cy + fName * 0.55} fontSize={fPct} fill="#fff" fontFamily="monospace"
                  fontWeight="700" textAnchor="middle" dominantBaseline="middle"
                  stroke="rgba(0,0,0,0.7)" strokeWidth={sw * 1.2} paintOrder="stroke">
                  {focoQty}
                </text>
              )}
            </g>
            );
          })}
        </>
      ) : heatmap ? (
        <>
          {boxData.map(({ key, hullStr, avgHeat }) => (
            <polygon key={key + "-r"} points={hullStr}
              fill={heatColor(avgHeat)} opacity={0.88}
              style={{ pointerEvents: "auto", cursor: "pointer" }} onDoubleClick={() => onSelect(key)} />
          ))}
          {boxData.map(({ key, cx, cy, avgHeat }) => (
            <g key={key + "-t"} style={{ pointerEvents: "none" }}>
              <text x={cx} y={cy - fPct * 0.30} fontSize={fName} fill="#fff" fontFamily="monospace"
                fontWeight="700" textAnchor="middle" dominantBaseline="middle"
                stroke="rgba(0,0,0,0.7)" strokeWidth={sw} paintOrder="stroke">
                SDM {key}
              </text>
              <text x={cx} y={cy + fPct * 0.48} fontSize={fPct} fill="#fff" fontFamily="monospace"
                fontWeight="700" textAnchor="middle" dominantBaseline="middle"
                stroke="rgba(0,0,0,0.7)" strokeWidth={sw * 1.5} paintOrder="stroke">
                {Math.round(avgHeat * 100)}%
              </text>
            </g>
          ))}
        </>
      ) : (
        <>
          {boxData.map(({ key, pct, hullStr }) => (
            <polygon key={key + "-fill"} points={hullStr}
              fill="rgba(16,23,41,0.72)" stroke={pct === 1 ? P.done : P.border} strokeWidth={2}
              style={{ cursor: "pointer", pointerEvents: "auto" }} onDoubleClick={() => onSelect(key)} />
          ))}
          {/* Pass 2: tracker dots */}
          {trackerDots.map(({ key, n, pt, val }) => (
            <rect key={key + "-" + n}
              x={pt.x - 4} y={pt.y - 9} width={8} height={18} rx={2}
              fill={STATE_COLORS[activeLayer][val]} opacity={0.95}
              style={{ pointerEvents: "none" }} />
          ))}
          {/* Pass 3: labels always on top of everything */}
          {boxData.map(({ key, bw, bh, cx, cy }) => bw > 24 && bh > 18 && (
            <text key={key + "-lbl"} x={cx} y={cy} fontSize={12} fill="#fff" fontFamily="monospace"
              fontWeight="700" textAnchor="middle" dominantBaseline="middle"
              stroke="rgba(0,0,0,0.9)" strokeWidth={3} paintOrder="stroke"
              style={{ pointerEvents: "none" }}>
              SDM {key}
            </text>
          ))}
        </>
      )}
    </svg>,
    map.getContainer()
  );
}

function ZoomWatcher({ onZoom }) {
  useMapEvents({ zoomend: (e) => onZoom(e.target.getZoom()) });
  return null;
}

function OverviewMap({ statuses, activeLayer, onSelect, heatmap, onZoomChange, focoType, focoVisit }) {
  return (
    <div style={{
      flex: 1, minHeight: 0, position: "relative",
      borderRadius: 12, overflow: "hidden", border: `1px solid ${P.border}`,
    }}>
      <MapContainer
        center={PLANT_CENTER_LL} zoom={15}
        style={{ width: "100%", height: "100%" }}
        zoomControl={true} attributionControl={false}
        zoomSnap={0.25} zoomDelta={0.5} wheelPxPerZoomLevel={120}
      >
        <TileLayer
          url="https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}"
          maxZoom={20} maxNativeZoom={19}
        />
        <ZoomWatcher onZoom={onZoomChange} />
        <PlantLayer
          statuses={statuses} activeLayer={activeLayer}
          onSelect={onSelect} heatmap={heatmap} focoType={focoType} focoVisit={focoVisit}
        />
      </MapContainer>
      {heatmap && (
        <div style={{
          position: "absolute", top: 10, right: 10, zIndex: 1000,
          background: "rgba(13,15,20,0.9)", border: `1px solid ${P.border}`,
          borderRadius: 8, padding: "8px 10px", pointerEvents: "none",
        }}>
          <div style={{ color: P.muted, fontSize: 10, fontFamily: "monospace", letterSpacing: 0.5, marginBottom: 6 }}>LEGENDA:</div>
          <div style={{ display: "flex", gap: 7, alignItems: "stretch" }}>
            <div style={{
              width: 12, height: 100, borderRadius: 3, flexShrink: 0,
              background: "linear-gradient(to bottom,rgb(0,195,30),rgb(110,195,30),rgb(220,190,30),rgb(220,95,30),rgb(220,0,30))",
            }} />
            <div style={{ display: "flex", flexDirection: "column", justifyContent: "space-between" }}>
              {["100%", "75%", "50%", "25%", "0%"].map((l) => (
                <span key={l} style={{ fontSize: 10, color: P.text, fontFamily: "monospace", lineHeight: 1 }}>{l}</span>
              ))}
            </div>
          </div>
        </div>
      )}
      {isFocosLayer(activeLayer) && (
        <div style={{
          position: "absolute", top: 10, right: 10, zIndex: 1000,
          background: "rgba(13,15,20,0.9)", border: `1px solid ${P.border}`,
          borderRadius: 8, padding: "8px 10px", pointerEvents: "none",
        }}>
          <div style={{ color: P.muted, fontSize: 10, fontFamily: "monospace", letterSpacing: 0.5, marginBottom: 6 }}>ESCALA:</div>
          <div style={{ display: "flex", gap: 7, alignItems: "center" }}>
            <span style={{ fontSize: 10, color: P.muted, fontFamily: "monospace" }}>Menor</span>
            <div style={{
              width: 80, height: 8, borderRadius: 4,
              background: "linear-gradient(to right, #facc15, #ff9b3d, #fa3d2d)",
            }} />
            <span style={{ fontSize: 10, color: P.muted, fontFamily: "monospace" }}>Maior</span>
          </div>
        </div>
      )}
    </div>
  );
}

function OverviewCards({ statuses, activeLayer, onSelect }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 10 }}>
      {SUB_KEYS.map((key) => {
        const stat = countDone(statuses, key, PLANT[key].t, activeLayer);
        const pct = stat.total ? Math.round((stat.done / stat.total) * 100) : 0;
        const colors = STATE_COLORS[activeLayer];
        return (
          <button key={key} onDoubleClick={() => onSelect(key)} style={{
            textAlign: "left", background: P.card, border: `1px solid ${pct === 100 ? P.accent + "77" : P.border}`,
            borderRadius: 10, padding: "12px 14px", cursor: "pointer", fontFamily: "inherit",
          }}>
            <div style={{ color: P.text, fontWeight: 700, fontSize: 14, marginBottom: 6 }}>SDM {key}</div>
            <ProgressBar done={stat.done} prog={stat.prog} total={stat.total} color={colors[LAYER_DONE_IDX[activeLayer]]} />
            <div style={{ color: P.muted, fontSize: 11, fontFamily: "monospace", marginTop: 6 }}>{stat.done}/{stat.total} · {pct}%</div>
          </button>
        );
      })}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   APP
   ════════════════════════════════════════════════════════════════════════ */
const STORAGE_ROW_ID = "sdm_tracker_status_v1";

const ADMIN_PASS = "Airbox2026";
const BG_IMG = "/WhatsApp Image 2026-06-23 at 10.44.57.jpeg";

function LoginOverlay({ phase, onLogin }) {
  const [pass, setPass] = useState("");
  const [error, setError] = useState(false);

  const handleLogin = (mode) => {
    if (mode === "admin") {
      if (pass !== ADMIN_PASS) { setError(true); setTimeout(() => setError(false), 1200); return; }
    }
    onLogin(mode === "admin");
  };

  const showCard = phase === "login";
  const showSpinner = phase === "loading";
  const fading = phase === "fadeout";

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      opacity: fading ? 0 : 1,
      transition: "opacity 0.8s ease",
      pointerEvents: fading ? "none" : "auto",
    }}>
      <div style={{
        position: "absolute", inset: 0,
        backgroundImage: `url("${BG_IMG}")`,
        backgroundSize: "cover", backgroundPosition: "center",
        filter: "brightness(0.4)",
      }} />

      {showCard && (
        <div style={{
          position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
          zIndex: 1, animation: "fadeSlideIn 0.5s ease",
        }}>
          <div style={{
            background: "rgba(11,15,30,0.82)", backdropFilter: "blur(24px)",
            border: "1px solid rgba(245,210,0,0.18)", borderRadius: 20,
            padding: "48px 44px 40px", width: 380, maxWidth: "90vw",
            display: "flex", flexDirection: "column", alignItems: "center", gap: 28,
            boxShadow: "0 24px 80px rgba(0,0,0,0.5)",
          }}>
            <img src="/logo-airbox.jpg" alt="Airbox" style={{ height: 52, borderRadius: 8 }} />

            <div style={{ textAlign: "center" }}>
              <div style={{ color: "#F5D200", fontSize: 20, fontWeight: 700, letterSpacing: 0.5, lineHeight: 1.3 }}>
                UFV Serra do Mato
              </div>
              <div style={{ color: "#7b8bad", fontSize: 11.5, letterSpacing: 1.5, fontFamily: "monospace", marginTop: 5 }}>
                Trairi/CE
              </div>
              <div style={{ width: 40, height: 2, background: "rgba(245,210,0,0.3)", borderRadius: 1, margin: "10px auto 0" }} />
              <div style={{ color: "#7b8bad", fontSize: 10, letterSpacing: 2, fontFamily: "monospace", marginTop: 8, textTransform: "uppercase" }}>
                Controle de Manutenção
              </div>
            </div>

            <div style={{ width: "100%", display: "flex", flexDirection: "column", gap: 12 }}>
              <div style={{ position: "relative" }}>
                <input
                  type="password" placeholder="Senha de acesso"
                  value={pass} onChange={(e) => setPass(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleLogin("admin")}
                  style={{
                    width: "100%", padding: "14px 16px", borderRadius: 12, fontSize: 14,
                    background: "rgba(16,23,41,0.9)", color: "#e8edf8",
                    border: `1.5px solid ${error ? "#ff5f7e" : "rgba(245,210,0,0.25)"}`,
                    outline: "none", fontFamily: "inherit",
                    transition: "border-color 0.3s",
                  }}
                />
                {error && (
                  <div style={{
                    position: "absolute", right: 14, top: "50%", transform: "translateY(-50%)",
                    color: "#ff5f7e", fontSize: 12, fontWeight: 600, fontFamily: "monospace",
                    animation: "shake 0.4s ease",
                  }}>Senha incorreta</div>
                )}
              </div>

              <button onClick={() => handleLogin("admin")} style={{
                width: "100%", padding: "14px 0", borderRadius: 12, border: "none",
                background: "linear-gradient(135deg, #F5D200, #C9AC00)", color: "#0b0f1e",
                fontSize: 14, fontWeight: 700, cursor: "pointer", fontFamily: "inherit",
                letterSpacing: 0.5,
              }}>
                Entrar
              </button>

              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <div style={{ flex: 1, height: 1, background: "rgba(123,139,173,0.25)" }} />
                <span style={{ color: "#7b8bad", fontSize: 11, fontFamily: "monospace" }}>ou</span>
                <div style={{ flex: 1, height: 1, background: "rgba(123,139,173,0.25)" }} />
              </div>

              <button onClick={() => handleLogin("visitor")} style={{
                width: "100%", padding: "12px 0", borderRadius: 12,
                border: "1.5px solid rgba(77,166,255,0.35)", background: "rgba(77,166,255,0.08)",
                color: "#4da6ff", fontSize: 13, fontWeight: 600, cursor: "pointer",
                fontFamily: "inherit", letterSpacing: 0.3,
              }}>
                Acessar como Visitante
              </button>
            </div>

            <div style={{ color: "rgba(123,139,173,0.35)", fontSize: 9, fontFamily: "monospace", letterSpacing: 1.5 }}>
              POWERED BY AIRBOX
            </div>
          </div>
        </div>
      )}

      {showSpinner && (
        <div style={{
          position: "absolute", inset: 0, display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center", gap: 20, zIndex: 1,
          animation: "fadeSlideIn 0.4s ease",
        }}>
          <div style={{ display: "flex", gap: 10 }}>
            {[0, 1, 2, 3, 4].map((i) => (
              <div key={i} style={{
                width: 12, height: 12, borderRadius: "50%", background: "#F5D200",
                animation: "dotPulse 1.4s ease-in-out infinite",
                animationDelay: `${i * 0.16}s`,
              }} />
            ))}
          </div>
          <div style={{ color: "rgba(245,210,0,0.7)", fontSize: 11, fontFamily: "monospace", letterSpacing: 2 }}>
            CARREGANDO
          </div>
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [overlayPhase, setOverlayPhase] = useState("login"); // login | loading | fadeout | done
  const [readOnly, setReadOnly] = useState(true);
  const [view, setView] = useState("overview");
  const [activeLayer, setActiveLayerRaw] = useState("lavagem");
  const [heatmap, setHeatmap] = useState(false);
  const [focoType, setFocoType] = useState("formigas");
  const [focoVisit, setFocoVisit] = useState("v1");
  const setActiveLayer = (layer) => {
    if (layer === "trator" || layer === "trackers" || isFocosLayer(layer)) setHeatmap(false);
    setActiveLayerRaw(layer);
  };
  const [mapZoom, setMapZoom] = useState(15);
  const [statuses, setStatuses] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [syncState, setSyncState] = useState("loading");
  const saveTimer = useRef(null);
  const skipNextRealtime = useRef(false);
  const userDirty = useRef(false);

  const handleLogin = useCallback((isAdmin) => {
    setReadOnly(!isAdmin);
    setOverlayPhase("loading");
    setTimeout(() => {
      setOverlayPhase("fadeout");
      setTimeout(() => setOverlayPhase("done"), 900);
    }, 1800);
  }, []);

  const setStatusesByUser = useCallback((updater) => {
    if (readOnly) return;
    userDirty.current = true;
    setStatuses(updater);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [readOnly]);

  useEffect(() => {
    let channel;
    (async () => {
      if (!supabase) {
        setSyncState("offline");
        setLoaded(true);
        return;
      }
      try {
        const { data, error } = await supabase
          .from("tracker_status")
          .select("value")
          .eq("id", STORAGE_ROW_ID)
          .maybeSingle();
        if (error) throw error;
        if (data && data.value) setStatuses(data.value);
        setSyncState("ok");
      } catch (e) {
        console.error("Erro ao carregar do Supabase:", e);
        setSyncState("error");
      }
      setLoaded(true);

      channel = supabase
        .channel("tracker_status_changes")
        .on(
          "postgres_changes",
          { event: "*", schema: "public", table: "tracker_status", filter: `id=eq.${STORAGE_ROW_ID}` },
          (payload) => {
            if (skipNextRealtime.current) { skipNextRealtime.current = false; return; }
            if (userDirty.current) return;
            if (payload.new && payload.new.value) setStatuses(payload.new.value);
          }
        )
        .subscribe();
    })();
    return () => { if (channel && supabase) supabase.removeChannel(channel); };
  }, []);

  useEffect(() => {
    if (!loaded || !supabase || !userDirty.current) return;
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(async () => {
      userDirty.current = false;
      setSyncState("saving");
      try {
        skipNextRealtime.current = true;
        const { error } = await supabase
          .from("tracker_status")
          .upsert({ id: STORAGE_ROW_ID, value: statuses, updated_at: new Date().toISOString() });
        if (error) throw error;
        setSyncState("ok");
      } catch (e) {
        userDirty.current = true;
        console.error("Erro ao salvar no Supabase:", e);
        setSyncState("error");
      }
    }, 800);
  }, [statuses, loaded]);

  const globalStat = useMemo(() => {
    if (isFocosLayer(activeLayer)) return { done: 0, prog: 0, total: 0 };
    const realLayer = activeLayer;
    const allPoints = SUB_KEYS.flatMap((k) => PLANT[k].t.map((t) => ({ key: k, n: t[0] })));
    const idx = LAYER_IDX[realLayer];
    let done = 0, prog = 0;
    const layer = LAYERS.find((l) => l.key === realLayer);
    if (!layer) return { done: 0, prog: 0, total: allPoints.length };
    allPoints.forEach((p) => {
      const v = getStatus(statuses, p.key, p.n)[idx];
      if (v === layer.doneIdx) done++;
      else if (layer.progIdxes.includes(v)) prog++;
    });
    return { done, prog, total: allPoints.length };
  }, [statuses, activeLayer]);

  return (
    <div style={{
      height: "100vh", background: P.bg, color: P.text,
      fontFamily: "'IBM Plex Sans','Segoe UI',sans-serif",
      display: "flex", flexDirection: "column", overflow: "hidden",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=IBM+Plex+Mono:wght@500;700&display=swap');
        *{box-sizing:border-box}
        code,.mono{font-family:'IBM Plex Mono',monospace}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.25}}
        @keyframes dotPulse{0%,80%,100%{opacity:.2;transform:scale(.7)}40%{opacity:1;transform:scale(1)}}
        @keyframes shake{0%,100%{transform:translateX(0) translateY(-50%)}20%,60%{transform:translateX(-6px) translateY(-50%)}40%,80%{transform:translateX(6px) translateY(-50%)}}
        @keyframes fadeSlideIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
        ::-webkit-scrollbar{width:7px;height:7px}::-webkit-scrollbar-track{background:${P.surface}}::-webkit-scrollbar-thumb{background:${P.border};border-radius:4px}
        select, input, button { font-family: inherit; }
        button:hover { filter: brightness(1.12); }
        html, body { margin: 0; padding: 0; height: 100%; overflow: hidden; background: #0b0f1e; }
      `}</style>

      {overlayPhase !== "done" && <LoginOverlay phase={overlayPhase} onLogin={handleLogin} />}

      <div style={{ flex: 1, display: "flex", flexDirection: "column", padding: "12px 16px", minHeight: 0 }}>

      <div style={{ display: "flex", flexDirection: "column", flex: 1, minHeight: 0 }}>
        <div style={{
          display: "flex", alignItems: "center", gap: 16, marginBottom: 10, flexShrink: 0,
          background: P.navy, borderRadius: 10, padding: "8px 16px",
          border: `1px solid ${P.accent}33`,
        }}>
          <img src="/logo-airbox.jpg" alt="Airbox" style={{ height: 32, borderRadius: 4, flexShrink: 0 }} />
          <div style={{ width: 1, height: 28, background: `${P.accent}44`, flexShrink: 0 }} />
          <div>
            <div style={{ color: P.accent, fontSize: 13, fontWeight: 700, letterSpacing: 0.5, lineHeight: 1.2 }}>
              UFV SDM — Serra do Mato
            </div>
            <div style={{ color: P.muted, fontSize: 10, letterSpacing: 1, fontFamily: "monospace" }}>
              CONTROLE DE MANUTENÇÃO
            </div>
          </div>
          <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 10 }}>
            {readOnly && (
              <span style={{
                background: P.info + "22", border: `1px solid ${P.info}55`, color: P.info,
                borderRadius: 99, padding: "3px 10px", fontSize: 10, fontWeight: 700,
                fontFamily: "monospace", letterSpacing: 0.5,
              }}>SOMENTE VISUALIZAÇÃO</span>
            )}
            <SyncBadge state={syncState} />
          </div>
        </div>

        {!loaded ? (
          <div style={{ color: P.muted, fontSize: 13 }}>Carregando status salvo...</div>
        ) : view === "overview" ? (
          <div style={{ display: "flex", flexDirection: "column", gap: 8, flex: 1, minHeight: 0 }}>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center", flexShrink: 0 }}>
              <LayerTabs active={activeLayer} onChange={setActiveLayer} />
              {(activeLayer === "pragas_c1" || activeLayer === "pragas_c2" || isFocosLayer(activeLayer)) && (
                <>
                  <PragasSubTabs active={activeLayer} onChange={setActiveLayer} />
                  {isFocosLayer(activeLayer) && <>
                    <FocoVisitChips active={focoVisit} onChange={setFocoVisit} />
                    <FocoTypeChips active={focoType} onChange={setFocoType} />
                  </>}
                </>
              )}
              {activeLayer !== "trator" && activeLayer !== "trackers" && !isFocosLayer(activeLayer) && (
                <button onClick={() => setHeatmap((h) => !h)} style={{
                  padding: "4px 10px", borderRadius: 7,
                  border: `1px solid ${heatmap ? P.accent + "55" : P.border}`,
                  cursor: "pointer", fontFamily: "inherit", fontSize: 11, fontWeight: 600,
                  background: heatmap ? P.accent : "transparent",
                  color: heatmap ? "#111827" : P.muted, transition: "all .12s",
                }}>
                  Heatmap
                </button>
              )}
              <div style={{ display: "flex", flexDirection: "column", gap: 4, marginLeft: "auto" }}>
                <button onClick={() => setActiveLayer(activeLayer === "trator" ? "lavagem" : "trator")} style={{
                  padding: "4px 10px", borderRadius: 7,
                  border: `1px solid ${activeLayer === "trator" ? P.warn + "66" : P.border}`,
                  cursor: "pointer", fontFamily: "inherit", fontSize: 11, fontWeight: 600,
                  background: activeLayer === "trator" ? P.warn + "22" : "transparent",
                  color: activeLayer === "trator" ? P.warn : P.muted, transition: "all .12s",
                }}>
                  Acesso trator
                </button>
                <button onClick={() => setActiveLayer(activeLayer === "trackers" ? "lavagem" : "trackers")} style={{
                  padding: "4px 10px", borderRadius: 7,
                  border: `1px solid ${activeLayer === "trackers" ? P.purple + "66" : P.border}`,
                  cursor: "pointer", fontFamily: "inherit", fontSize: 11, fontWeight: 600,
                  background: activeLayer === "trackers" ? P.purple + "22" : "transparent",
                  color: activeLayer === "trackers" ? P.purple : P.muted, transition: "all .12s",
                }}>
                  Trackers
                </button>
              </div>
            </div>
            {!heatmap && mapZoom >= 16 && activeLayer !== "trackers" && !isFocosLayer(activeLayer) && <Legend activeLayer={activeLayer} />}
            <OverviewMap statuses={statuses} activeLayer={activeLayer} onSelect={setView} heatmap={heatmap} onZoomChange={setMapZoom}
              focoType={focoType} focoVisit={focoVisit} />
          </div>
        ) : (
          <div style={{ flex: 1, minHeight: 0 }}>
            <SubcampoView key={view} subKey={view} statuses={statuses} setStatuses={setStatusesByUser}
              activeLayer={activeLayer} setActiveLayer={setActiveLayer}
              onNavigate={(key) => setView(key || "overview")} readOnly={readOnly}
              focoType={focoType} setFocoType={setFocoType}
              focoVisit={focoVisit} setFocoVisit={setFocoVisit} />
          </div>
        )}
      </div>
      </div>
    </div>
  );
}
